/// <summary>
///    The <c>ETGTermoNumberReportController</c> class is the helper class for the associated  report.
/// </summary>
public class ETGTermoNumberReportController extends SrsReportRunController
{
    ETGTermoNumberReportContract                        contract;
    ModuleSalesPurch                                    moduleType;

}

Method.Source:
protected void preRunModifyContract()
{
    contract = this.parmReportContract().parmRdpContract();
    switch (args.menuItemName())
    {
        case  menuItemOutputStr(ETGTermoNumberReport):
            moduleType = ModuleSalesPurch::Sales;
            contract.parmModuleSalesPurch(moduleType);
            break;
        case  menuItemOutputStr(ETGTermoNumberReportPurchase):
            moduleType = ModuleSalesPurch::Purch;
            contract.parmModuleSalesPurch(moduleType);
            break;
        default:
            throw error(Error::wrongUseOfFunction(funcName()));
    }
}

/// </summary>
/// <param name="_args">
/// The <c>Args</c> object.
/// </param>
public static void main(Args _args)
{
    ETGTermoNumberReportController termoReportController = new ETGTermoNumberReportController();

    termoReportController.parmArgs(_args);
    switch (_args.menuItemName())
    {
        case  menuItemOutputStr(ETGTermoNumberReport):
            termoReportController.parmReportName(ssrsReportStr(ETGTermoNumberReport, SalesInvoice));
            break;
        case  menuItemOutputStr(ETGTermoNumberReportPurchase):
            termoReportController.parmReportName(ssrsReportStr(ETGTermoNumberReport, PurchInvoice));
            break;
        default:
            throw error(Error::wrongUseOfFunction(funcName()));
    }
    termoReportController.parmLoadFromSysLastValue(false);
    termoReportController.parmShowDialog(true);
    termoReportController.parmDialogCaption("@ETG_New:TERMONumberReport");
    termoReportController.startOperation();
}
